use crate::types::{DecideInput, DecideOutput};

#[derive(PartialEq, Debug)]
pub enum CompType {
    LT,
    EQ,
    GT,
}

pub fn realcompare(a: f64, b: f64) -> CompType {
    let epsilon = 0.000001;
    if (a - b).abs() < epsilon {
        CompType::EQ
    } else if a < b {
        CompType::LT
    } else {
        CompType::GT
    }
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = vec![false; 15];

    // LIC 1
    for i in 0..input.numpoints - 1 {
        let dist = ((input.x[i+1] - input.x[i]).powi(2) + (input.y[i+1] - input.y[i]).powi(2)).sqrt();
        if realcompare(dist, input.parameters.length1) == CompType::GT {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2
    for i in 0..input.numpoints - 2 {
        if !is_contained_in_circle(
            (input.x[i], input.y[i]),
            (input.x[i+1], input.y[i+1]),
            (input.x[i+2], input.y[i+2]),
            input.parameters.radius1
        ) {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3
    for i in 0..input.numpoints - 2 {
        let (p1, p2, p3) = ((input.x[i], input.y[i]), (input.x[i+1], input.y[i+1]), (input.x[i+2], input.y[i+2]));
        if is_angle_defined(p1, p2, p3) {
            let angle = get_angle(p1, p2, p3);
            if realcompare(angle, std::f64::consts::PI - input.parameters.epsilon) == CompType::LT ||
               realcompare(angle, std::f64::consts::PI + input.parameters.epsilon) == CompType::GT {
                cmv[2] = true;
                break;
            }
        }
    }

    // LIC 4
    for i in 0..input.numpoints - 2 {
        let area = get_triangle_area((input.x[i], input.y[i]), (input.x[i+1], input.y[i+1]), (input.x[i+2], input.y[i+2]));
        if realcompare(area, input.parameters.area1) == CompType::GT {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5
    for i in 0..=input.numpoints - input.parameters.q_pts {
        let mut quadrants = std::collections::HashSet::new();
        for j in 0..input.parameters.q_pts {
            quadrants.insert(get_quadrant(input.x[i+j], input.y[i+j]));
        }
        if quadrants.len() > input.parameters.quads {
            cmv[4] = true;
            break;
        }
    }

    // LIC 6
    if input.numpoints >= 3 {
        for i in 0..input.numpoints - 1 {
            if realcompare(input.x[i+1] - input.x[i], 0.0) == CompType::LT {
                cmv[5] = true;
                break;
            }
        }
    }

    // LIC 7
    if input.numpoints >= 3 {
        for i in 0..=input.numpoints - input.parameters.n_pts {
            let p_start = (input.x[i], input.y[i]);
            let p_end = (input.x[i + input.parameters.n_pts - 1], input.y[i + input.parameters.n_pts - 1]);
            for j in i + 1..i + input.parameters.n_pts - 1 {
                let dist = get_dist_point_to_line((input.x[j], input.y[j]), p_start, p_end);
                if realcompare(dist, input.parameters.dist) == CompType::GT {
                    cmv[6] = true;
                    break;
                }
            }
        }
    }

    // LIC 8
    if input.numpoints >= 3 {
        let k = input.parameters.k_pts;
        for i in 0..input.numpoints - k - 1 {
            let dist = ((input.x[i+k+1] - input.x[i]).powi(2) + (input.y[i+k+1] - input.y[i]).powi(2)).sqrt();
            if realcompare(dist, input.parameters.length1) == CompType::GT {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if input.numpoints >= 5 {
        let a = input.parameters.a_pts;
        let b = input.parameters.b_pts;
        for i in 0..input.numpoints - a - b - 2 {
            if !is_contained_in_circle(
                (input.x[i], input.y[i]),
                (input.x[i+a+1], input.y[i+a+1]),
                (input.x[i+a+b+2], input.y[i+a+b+2]),
                input.parameters.radius1
            ) {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if input.numpoints >= 5 {
        let c = input.parameters.c_pts;
        let d = input.parameters.d_pts;
        for i in 0..input.numpoints - c - d - 2 {
            let (p1, p2, p3) = (
                (input.x[i], input.y[i]),
                (input.x[i+c+1], input.y[i+c+1]),
                (input.x[i+c+d+2], input.y[i+c+d+2])
            );
            if is_angle_defined(p1, p2, p3) {
                let angle = get_angle(p1, p2, p3);
                if realcompare(angle, std::f64::consts::PI - input.parameters.epsilon) == CompType::LT ||
                   realcompare(angle, std::f64::consts::PI + input.parameters.epsilon) == CompType::GT {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11
    if input.numpoints >= 5 {
        let e = input.parameters.e_pts;
        let f = input.parameters.f_pts;
        for i in 0..input.numpoints - e - f - 2 {
            let area = get_triangle_area(
                (input.x[i], input.y[i]),
                (input.x[i+e+1], input.y[i+e+1]),
                (input.x[i+e+f+2], input.y[i+e+f+2])
            );
            if realcompare(area, input.parameters.area1) == CompType::GT {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12
    if input.numpoints >= 3 {
        let g = input.parameters.g_pts;
        for i in 0..input.numpoints - g - 1 {
            if realcompare(input.x[i+g+1] - input.x[i], 0.0) == CompType::LT {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13
    if input.numpoints >= 3 {
        let k = input.parameters.k_pts;
        let mut cond1 = false;
        let mut cond2 = false;
        for i in 0..input.numpoints - k - 1 {
            let dist = ((input.x[i+k+1] - input.x[i]).powi(2) + (input.y[i+k+1] - input.y[i]).powi(2)).sqrt();
            if realcompare(dist, input.parameters.length1) == CompType::GT { cond1 = true; }
            if realcompare(dist, input.parameters.length2) == CompType::LT { cond2 = true; }
        }
        if cond1 && cond2 { cmv[12] = true; }
    }

    // LIC 14
    if input.numpoints >= 5 {
        let a = input.parameters.a_pts;
        let b = input.parameters.b_pts;
        let mut cond1 = false;
        let mut cond2 = false;
        for i in 0..input.numpoints - a - b - 2 {
            let p1 = (input.x[i], input.y[i]);
            let p2 = (input.x[i+a+1], input.y[i+a+1]);
            let p3 = (input.x[i+a+b+2], input.y[i+a+b+2]);
            if !is_contained_in_circle(p1, p2, p3, input.parameters.radius1) { cond1 = true; }
            if is_contained_in_circle(p1, p2, p3, input.parameters.radius2) { cond2 = true; }
        }
        if cond1 && cond2 { cmv[13] = true; }
    }

    // LIC 15
    if input.numpoints >= 5 {
        let e = input.parameters.e_pts;
        let f = input.parameters.f_pts;
        let mut cond1 = false;
        let mut cond2 = false;
        for i in 0..input.numpoints - e - f - 2 {
            let area = get_triangle_area(
                (input.x[i], input.y[i]),
                (input.x[i+e+1], input.y[i+e+1]),
                (input.x[i+e+f+2], input.y[i+e+f+2])
            );
            if realcompare(area, input.parameters.area1) == CompType::GT { cond1 = true; }
            if realcompare(area, input.parameters.area2) == CompType::LT { cond2 = true; }
        }
        if cond1 && cond2 { cmv[14] = true; }
    }

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
                continue;
            }
            let connector = &input.lcm[i][j];
            match connector.as_str() {
                "NOTUSED" => { pum[i][j] = true; }
                "ANDD" => { pum[i][j] = cmv[i] && cmv[j]; }
                "ORR" => { pum[i][j] = cmv[i] || cmv[j]; }
                _ => {}
            }
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !input.pum_diag[i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&x| x);
        }
    }

    let launch = fuv.iter().all(|&x| x);
    DecideOutput::from_fixed(cmv, pum, fuv, launch)
}

fn get_quadrant(x: f64, y: f64) -> usize {
    if x >= 0.0 && y >= 0.0 { 1 }
    else if x < 0.0 && y >= 0.0 { 2 }
    else if x < 0.0 && y < 0.0 { 3 }
    else { 4 }
}

fn get_triangle_area(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    0.5 * (p1.0 * (p2.1 - p3.1) + p2.0 * (p3.1 - p1.1) + p3.0 * (p1.1 - p2.1)).abs()
}

fn get_dist_point_to_line(p: (f64, f64), l1: (f64, f64), l2: (f64, f64)) -> f64 {
    if realcompare(l1.0, l2.0) == CompType::EQ && realcompare(l1.1, l2.1) == CompType::EQ {
        return ((p.0 - l1.0).powi(2) + (p.1 - l1.1).powi(2)).sqrt();
    }
    ((l2.1 - l1.1) * p.0 - (l2.0 - l1.0) * p.1 + l2.0 * l1.1 - l2.1 * l1.0).abs() /
    ((l2.1 - l1.1).powi(2) + (l2.0 - l1.0).powi(2)).sqrt()
}

fn is_angle_defined(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> bool {
    !( (realcompare(p1.0, p2.0) == CompType::EQ && realcompare(p1.1, p2.1) == CompType::EQ) ||
       (realcompare(p3.0, p2.0) == CompType::EQ && realcompare(p3.1, p2.1) == CompType::EQ) )
}

fn get_angle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let angle1 = (p1.1 - p2.1).atan2(p1.0 - p2.0);
    let angle2 = (p3.1 - p2.1).atan2(p3.0 - p2.0);
    let mut angle = (angle1 - angle2).abs();
    if angle > std::f64::consts::PI {
        angle = 2.0 * std::f64::consts::PI - angle;
    }
    angle
}

fn is_contained_in_circle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64), radius: f64) -> bool {
    // Check if any pair distance is > 2 * radius
    let d12 = ((p1.0 - p2.0).powi(2) + (p1.1 - p2.1).powi(2)).sqrt();
    let d23 = ((p2.0 - p3.0).powi(2) + (p2.1 - p3.1).powi(2)).sqrt();
    let d13 = ((p1.0 - p3.0).powi(2) + (p1.1 - p3.1).powi(2)).sqrt();

    if realcompare(d12, 2.0 * radius) == CompType::GT ||
       realcompare(d23, 2.0 * radius) == CompType::GT ||
       realcompare(d13, 2.0 * radius) == CompType::GT {
        return false;
    }

    // Smallest enclosing circle check
    let circumradius = get_circumradius(p1, p2, p3);
    if let Some(r) = circumradius {
        realcompare(r, radius) != CompType::GT
    } else {
        // Collinear or coincident: already checked pair distances,
        // if points are collinear, the longest segment is the diameter.
        let max_dist = d12.max(d23).max(d13);
        realcompare(max_dist, 2.0 * radius) != CompType::GT
    }
}

fn get_circumradius(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> Option<f64> {
    let a = ((p2.0 - p3.0).powi(2) + (p2.1 - p3.1).powi(2)).sqrt();
    let b = ((p1.0 - p3.0).powi(2) + (p1.1 - p3.1).powi(2)).sqrt();
    let c = ((p1.0 - p2.0).powi(2) + (p1.1 - p2.1).powi(2)).sqrt();

    let area = get_triangle_area(p1, p2, p3);
    if realcompare(area, 0.0) == CompType::EQ {
        return None;
    }
    Some((a * b * c) / (4.0 * area))
}
